        else if (_dateStartMonth != dateNull() && _dateEndMonth == dateNull())
        {
            projectRevenueLineTableDS.addRange(fieldNum(Cent_ProjectRevenueLineTable, TransDateMonth)).value(strFmt("%1..", _dateStartMonth));
        }
        else if (_dateStartMonth == dateNull() && _dateEndMonth != dateNull())
        {
            projectRevenueLineTableDS.addRange(fieldNum(Cent_ProjectRevenueLineTable, TransDateMonth)).value(strFmt("..%1", _dateEndMonth));
        }

        this.setProjectRevenueTempTable(query);
    }
